const item = $input.first() ?? { json: {}, binary: {} };
const json = { ...(item.json ?? {}) };
const binary = { ...(item.binary ?? {}) };

const refinementRaw = json.refinement ?? json.isRefinementInteraction;
const refinement = typeof refinementRaw === 'boolean'
  ? refinementRaw
  : ['true', '1', 'yes', 'y', 'refine'].includes(String(refinementRaw ?? '').trim().toLowerCase());

if (!String(json.reviewMode ?? '').trim()) {
  json.reviewMode = refinement ? 'refine' : '';
}

if (!binary.requirements && binary.requirementsFile) {
  binary.requirements = binary.requirementsFile;
}

if (!binary.requirements) {
  const requirementsText = String(json.requirements ?? '').trim();
  if (requirementsText) {
    binary.requirements = {
      data: Buffer.from(requirementsText, 'utf8').toString('base64'),
      fileName: 'requirements.md',
      mimeType: 'text/markdown',
    };
  }
}

if (!binary.openapiSpec && binary.api) {
  binary.openapiSpec = binary.api;
}

if (!binary.openapiSpec && binary.openapi) {
  binary.openapiSpec = binary.openapi;
}

if (!binary.openapiSpec && binary.openapiSpecFile) {
  binary.openapiSpec = binary.openapiSpecFile;
}

if (!binary.openapiSpec && binary.apiFile) {
  binary.openapiSpec = binary.apiFile;
}

if (!binary.openapiSpec) {
  const apiText = String(json.api ?? json.openapiSpec ?? '').trim();
  if (apiText) {
    binary.openapiSpec = {
      data: Buffer.from(apiText, 'utf8').toString('base64'),
      fileName: 'openapi.yaml',
      mimeType: 'application/yaml',
    };
  }
}

if (String(json.Feedback ?? '').trim() && !String(json.feedback ?? '').trim()) {
  json.feedback = String(json.Feedback).trim();
}

if (!json.refinement && typeof json.isRefinementInteraction !== 'undefined') {
  json.refinement = refinement;
}

for (const key of ['Approved', 'Start Again']) {
  delete json[key];
}

delete json.requirementsFile;
delete json.apiFile;
delete json.openapiSpecFile;
delete json.isRefinementInteraction;

const cleanedBinary = { ...binary };

// Never carry stale generated artefacts into the next generation cycle.
delete cleanedBinary.reviewZip;
delete cleanedBinary.outTokens;

return [{
  json,
  ...(Object.keys(cleanedBinary).length ? { binary: cleanedBinary } : {}),
}];

const branchItem = $input.first() ?? { json: {}, binary: {} };

function getNodeItemSafe(nodeName) {
  if (typeof $items !== 'function') return null;
  try {
    return ($items(nodeName) || [])[0] || null;
  } catch {
    return null;
  }
}

const contextItem = getNodeItemSafe('FE - Sanitize Output Context') ?? { json: {}, binary: {} };

const mergedJson = {
  ...(contextItem.json ?? {}),
  ...(branchItem.json ?? {}),
};

const mergedBinary = {
  ...(contextItem.binary ?? {}),
  ...(branchItem.binary ?? {}),
};

if (!mergedBinary.requirements) {
  throw new Error('Missing requirements binary before frontend prompt generation.');
}

if (!mergedBinary.openapiSpec) {
  throw new Error('Missing openapiSpec binary before frontend prompt generation.');
}

return [{
  json: mergedJson,
  ...(Object.keys(mergedBinary).length ? { binary: mergedBinary } : {}),
}];

const branchItem = $input.first() ?? { json: {}, binary: {} };

function getNodeItemSafe(nodeName) {
  if (typeof $items !== 'function') return null;
  try {
    return ($items(nodeName) || [])[0] || null;
  } catch {
    return null;
  }
}

const contextItem = getNodeItemSafe('FE - Sanitize Output Context') ?? { json: {}, binary: {} };

const mergedJson = {
