}];

async function feCompactContextArtifacts() {
  const items = $input.all();
  if (!items.length) {
    throw new Error('Frontend context compactor received no input.');
  }

  async function readBinaryText(itemIndex, propertyName, fallbackFileName) {
    const item = items[itemIndex];
    const binary = item.binary?.[propertyName];
    if (!binary) return null;
    const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, propertyName);
    return {
      fileName: binary.fileName || fallbackFileName,
      text: buffer.toString('utf8'),
    };
  }

  function cleanText(value) {
    return String(value || '').replace(/\s+/g, ' ').trim();
  }

  function slugify(value, fallback) {
    const text = cleanText(value).toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '');
    return text || fallback;
  }

  function normalizeText(text) {
    return String(text || '').replace(/\u0000/g, '').replace(/\r\n/g, '\n').replace(/\r/g, '\n').trim();
  }

  function isText(element) {
    return element && element.type === 'text' && cleanText(element.text);
  }

  function isRectangleLike(element) {
    return element && (element.type === 'rectangle' || element.type === 'frame');
  }

  function within(element, box, margin = 0) {
    const x = Number(element.x || 0);
    const y = Number(element.y || 0);
    return x >= box.x - margin && y >= box.y - margin && x <= box.x + box.width + margin && y <= box.y + box.height + margin;
  }

  function boxOf(element) {
    return {
      x: Number(element.x || 0),
      y: Number(element.y || 0),
      width: Number(element.width || 0),
      height: Number(element.height || 0),
    };
  }

  function area(box) {
    return Math.max(0, box.width) * Math.max(0, box.height);
  }

  function topColors(elements, key, limit) {
    const counts = new Map();
    for (const element of elements) {
      const value = String(element?.[key] || '').trim();
      if (!value || value === 'transparent') continue;
      counts.set(value, (counts.get(value) || 0) + 1);
    }
    return [...counts.entries()].sort((a, b) => b[1] - a[1]).slice(0, limit).map(([value]) => value);
  }

  function textElements(elements) {
    return elements.filter(isText).map((element) => ({
      text: cleanText(element.text),
      x: Number(element.x || 0),
      y: Number(element.y || 0),
      fontSize: Number(element.fontSize || 0),
      width: Number(element.width || 0),
      height: Number(element.height || 0),
    }));
  }

  function pickTitle(texts, box, fallback) {
    const candidates = texts
      .filter((text) => text.y <= box.y + Math.max(120, box.height * 0.18))
      .sort((a, b) => (b.fontSize - a.fontSize) || (a.y - b.y) || (a.x - b.x));
    return candidates.length ? candidates[0].text : fallback;
  }

  function uniqueLabels(values, limit) {
    const seen = new Set();
    const result = [];
    for (const value of values) {
      const normalized = cleanText(value);
      if (!normalized || seen.has(normalized)) continue;
      seen.add(normalized);
      result.push(normalized);
      if (result.length >= limit) break;
    }
    return result;
  }

  function uniqueObjects(values, limit, keyFn) {
    const seen = new Set();
    const result = [];
    for (const value of values) {
      const key = keyFn(value);
      if (!key || seen.has(key)) continue;
      seen.add(key);
      result.push(value);
      if (result.length >= limit) break;
    }
    return result;
  }

  function textsInside(texts, box) {
    return texts.filter((text) => within(text, box, 4)).sort((a, b) => (a.y - b.y) || (a.x - b.x));
  }

  function rectsInside(elements, box, predicate) {
    return elements
      .filter((element) => isRectangleLike(element) && within(element, box, 4) && predicate(element))
      .sort((a, b) => (Number(a.y || 0) - Number(b.y || 0)) || (Number(a.x || 0) - Number(b.x || 0)));
  }

  function nearestLabel(rect, texts) {
    const rectBox = boxOf(rect);
    const candidates = texts
      .filter((text) => text.x >= rectBox.x - 40 && text.x <= rectBox.x + rectBox.width + 20 && text.y >= rectBox.y - 48 && text.y <= rectBox.y + 14)
      .sort((a, b) => (Math.abs(rectBox.y - a.y) - Math.abs(rectBox.y - b.y)) || (a.x - b.x));
    return candidates.length ? candidates[0].text : null;
  }

  function fieldSummary(elements, texts, box) {
    const result = [];
    for (const rect of rectsInside(elements, box, (rect) => {
      const width = Number(rect.width || 0);
      const height = Number(rect.height || 0);
      return width >= 120 && width <= 640 && height >= 28 && height <= 96;
    })) {
      const label = nearestLabel(rect, texts);
      if (!label) continue;
      result.push({ label: cleanText(label), kind: 'field' });
      if (result.length >= 24) break;
    }
    return uniqueObjects(result, 24, (entry) => entry.label);
  }

  function tableSummary(elements, texts, box) {
    const result = [];
    for (const rect of rectsInside(elements, box, (rect) => Number(rect.width || 0) >= 420 && Number(rect.height || 0) >= 160)) {
      const rectBox = boxOf(rect);
      const innerTexts = textsInside(texts, rectBox);
      if (innerTexts.length < 8) continue;
      const headerTexts = innerTexts.filter((text) => text.y <= rectBox.y + 72).map((text) => text.text);
      result.push({ kind: 'table', columns: uniqueLabels(headerTexts, 10) });
      if (result.length >= 6) break;
    }
    return result;
  }

  function summarizeContainer(container, allElements, allTexts, index, kind) {
    const box = boxOf(container);
    const texts = textsInside(allTexts, box);
    const fallbackTitle = `${kind === 'dialog' ? 'Dialog' : 'Screen'} ${index + 1}`;
    const title = pickTitle(texts, box, fallbackTitle);
    const navTexts = texts.filter((text) => text.y <= box.y + 110 && text.text !== title).map((text) => text.text);
    const keyTexts = texts.filter((text) => text.text !== title).slice(0, 30).map((text) => text.text);
    return {
      id: slugify(title, `${kind}-${index + 1}`),
      title,
      kind,
      size: { width: box.width, height: box.height },
      nav: uniqueLabels(navTexts, 12),
      fields: fieldSummary(allElements, allTexts, box),
      tables: tableSummary(allElements, allTexts, box),
      keyTexts: uniqueLabels(keyTexts, 30),
    };
  }

  function summarizeDesign(designObject) {
    const elements = Array.isArray(designObject?.elements) ? designObject.elements : [];
    const texts = textElements(elements);
    const rectangles = elements.filter(isRectangleLike);

    const screenCandidates = rectangles
      .filter((rect) => Number(rect.width || 0) >= 900 && Number(rect.height || 0) >= 600)
      .sort((a, b) => area(boxOf(b)) - area(boxOf(a)));

    const screens = [];
    for (const candidate of screenCandidates) {
      const box = boxOf(candidate);
      const isNested = screens.some((existing) => {
        const existingBox = boxOf(existing);
        return box.x >= existingBox.x && box.y >= existingBox.y && box.x + box.width <= existingBox.x + existingBox.width && box.y + box.height <= existingBox.y + existingBox.height;
      });
      if (!isNested) screens.push(candidate);
      if (screens.length >= 12) break;
    }

    const screenBoxes = screens.map(boxOf);
    const dialogCandidates = rectangles.filter((rect) => {
      const width = Number(rect.width || 0);
      const height = Number(rect.height || 0);
      if (width < 280 || width > 1000 || height < 160 || height > 800) return false;
      const box = boxOf(rect);
      return !screenBoxes.some((screenBox) => box.x === screenBox.x && box.y === screenBox.y && box.width === screenBox.width && box.height === screenBox.height);
    }).slice(0, 20);

    const summarizedScreens = screens.length
      ? screens.map((screen, index) => summarizeContainer(screen, elements, texts, index, 'screen'))
      : [{
          id: 'screen-1',
          title: 'Primary Screen',
          kind: 'screen',
          size: { width: 0, height: 0 },
          nav: [],
          fields: [],
          tables: [],
          keyTexts: uniqueLabels(texts.slice(0, 60).map((text) => text.text), 60),
        }];

    const summarizedDialogs = dialogCandidates.map((dialog, index) => summarizeContainer(dialog, elements, texts, index, 'dialog'));

    return {
      meta: {
        sourceFormat: 'Excalidraw',
        originalElementCount: elements.length,
        screenCount: summarizedScreens.length,
        dialogCount: summarizedDialogs.length,
      },
      theme: {
        topStrokeColors: topColors(elements, 'strokeColor', 8),
        topFillColors: topColors(elements, 'backgroundColor', 8),
      },
      screens: summarizedScreens,
      dialogs: summarizedDialogs,
      looseTexts: uniqueLabels(texts.filter((text) => text.text.length >= 3).map((text) => text.text), 80),
    };
  }

  function binaryFromText(propertyName, fileName, text, mimeType) {
    return [
      propertyName,
      {
        data: Buffer.from(String(text || ''), 'utf8').toString('base64'),
        fileName,
        mimeType,
      },
    ];
  }
  function compactRequirementsText(text) {
    return String(text || '')
      .replace(/\\u0000/g, '')
      .replace(/\\r\\n/g, '\\n')
      .replace(/\\r/g, '\\n')
      .replace(/[ \\t]+/g, ' ')
      .trim();
  }

  function compactOpenapiText(text) {
    const normalized = normalizeText(text);
    if (!normalized) return '';
    if (normalized.startsWith('{')) {
      try {
        return JSON.stringify(JSON.parse(normalized));
      } catch {}
    }
    return normalized.replace(/[ \\t]+$/gm, '').replace(/\\n{3,}/g, '\\n\\n');
  }
  let requirements = null;
  let openapi = null;
  let design = null;
  for (let itemIndex = 0; itemIndex < items.length; itemIndex += 1) {
    if (!requirements) requirements = await readBinaryText.call(this, itemIndex, 'requirements', 'requirements-compact.txt');
    if (!openapi) openapi = await readBinaryText.call(this, itemIndex, 'openapiSpec', 'openapi-compact.json');
    if (!design) design = await readBinaryText.call(this, itemIndex, 'design', 'design.excalidraw.json');
  }

  if (!requirements) throw new Error('Missing compact requirements binary for frontend context.');
  if (!openapi) throw new Error('Missing compact openapiSpec binary for frontend context.');
  if (!design) throw new Error('Missing design binary for frontend context.');
  const compactedRequirementsText = compactRequirementsText(requirements.text);
  if (!compactedRequirementsText) throw new Error('Requirements text is empty after frontend compaction.');
  const compactedOpenapiText = compactOpenapiText(openapi.text);
  if (!compactedOpenapiText) throw new Error('OpenAPI text is empty after frontend compaction.');

  const designRaw = normalizeText(design.text);
  if (!designRaw) {
    throw new Error('Design text is empty, cannot compact frontend design context.');
  }

  let designObject;
  try {
    designObject = JSON.parse(designRaw);
  } catch (error) {
    throw new Error('Failed to parse design JSON for frontend context compaction: ' + String(error?.message || error));
  }

  const compactedDesign = summarizeDesign(designObject);
  const compactedDesignText = JSON.stringify(compactedDesign);

  return [{
    json: {
      designCompactionStats: {
        sourceBytes: Buffer.byteLength(designRaw, 'utf8'),
        compactBytes: Buffer.byteLength(compactedDesignText, 'utf8'),
        screenCount: compactedDesign.meta.screenCount,
        dialogCount: compactedDesign.meta.dialogCount,
      },
    },
    binary: Object.fromEntries([
      binaryFromText('requirements', 'requirements-compact.txt', compactedRequirementsText, 'text/plain'),
      binaryFromText('openapiSpec', 'openapi-compact.json', compactedOpenapiText, 'application/json'),
      binaryFromText('designSpec', 'design-compact.json', compactedDesignText, 'application/json'),
    ]),
  }];
}

return await feCompactContextArtifacts.call(this);

async function feCompactContextArtifacts() {
  const items = $input.all();
  if (!items.length) {
    throw new Error('Frontend context compactor received no input.');
  }

  async function readBinaryText(itemIndex, propertyName, fallbackFileName) {
    const item = items[itemIndex];
    const binary = item.binary?.[propertyName];
    if (!binary) return null;
    const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, propertyName);
    return {
      fileName: binary.fileName || fallbackFileName,
      text: buffer.toString('utf8'),
