    return element && element.type === 'text' && cleanText(element.text);
  }

  function isRectangleLike(element) {
    return element && (element.type === 'rectangle' || element.type === 'frame');
  }

  function within(element, box, margin = 0) {
    const x = Number(element.x || 0);
    const y = Number(element.y || 0);
    return x >= box.x - margin && y >= box.y - margin && x <= box.x + box.width + margin && y <= box.y + box.height + margin;
  }

  function boxOf(element) {
    return {
      x: Number(element.x || 0),
      y: Number(element.y || 0),
      width: Number(element.width || 0),
      height: Number(element.height || 0),
    };
  }

  function area(box) {
    return Math.max(0, box.width) * Math.max(0, box.height);
  }

  function topColors(elements, key, limit) {
    const counts = new Map();
    for (const element of elements) {
      const value = String(element?.[key] || '').trim();
      if (!value || value === 'transparent') continue;
      counts.set(value, (counts.get(value) || 0) + 1);
    }
    return [...counts.entries()].sort((a, b) => b[1] - a[1]).slice(0, limit).map(([value]) => value);
  }

  function textElements(elements) {
    return elements.filter(isText).map((element) => ({
      text: cleanText(element.text),
      x: Number(element.x || 0),
      y: Number(element.y || 0),
      fontSize: Number(element.fontSize || 0),
      width: Number(element.width || 0),
      height: Number(element.height || 0),
    }));
  }

  function pickTitle(texts, box, fallback) {
    const candidates = texts
      .filter((text) => text.y <= box.y + Math.max(120, box.height * 0.18))
      .sort((a, b) => (b.fontSize - a.fontSize) || (a.y - b.y) || (a.x - b.x));
    return candidates.length ? candidates[0].text : fallback;
  }

  function uniqueLabels(values, limit) {
    const seen = new Set();
    const result = [];
    for (const value of values) {
      const normalized = cleanText(value);
      if (!normalized || seen.has(normalized)) continue;
      seen.add(normalized);
      result.push(normalized);
      if (result.length >= limit) break;
    }
    return result;
  }

  function uniqueObjects(values, limit, keyFn) {
    const seen = new Set();
    const result = [];
    for (const value of values) {
      const key = keyFn(value);
      if (!key || seen.has(key)) continue;
      seen.add(key);
      result.push(value);
      if (result.length >= limit) break;
    }
    return result;
  }

  function textsInside(texts, box) {
    return texts.filter((text) => within(text, box, 4)).sort((a, b) => (a.y - b.y) || (a.x - b.x));
  }

  function rectsInside(elements, box, predicate) {
    return elements
      .filter((element) => isRectangleLike(element) && within(element, box, 4) && predicate(element))
      .sort((a, b) => (Number(a.y || 0) - Number(b.y || 0)) || (Number(a.x || 0) - Number(b.x || 0)));
  }

  function nearestLabel(rect, texts) {
    const rectBox = boxOf(rect);
    const candidates = texts
      .filter((text) => text.x >= rectBox.x - 40 && text.x <= rectBox.x + rectBox.width + 20 && text.y >= rectBox.y - 48 && text.y <= rectBox.y + 14)
      .sort((a, b) => (Math.abs(rectBox.y - a.y) - Math.abs(rectBox.y - b.y)) || (a.x - b.x));
    return candidates.length ? candidates[0].text : null;
  }

  function fieldSummary(elements, texts, box) {
    const result = [];
    for (const rect of rectsInside(elements, box, (rect) => {
