  }

  function summarizeContainer(container, allElements, allTexts, index, kind) {
    const box = boxOf(container);
    const texts = textsInside(allTexts, box);
    const fallbackTitle = `${kind === 'dialog' ? 'Dialog' : 'Screen'} ${index + 1}`;
