    }).slice(0, 20);

    const summarizedScreens = screens.length
      ? screens.map((screen, index) => summarizeContainer(screen, elements, texts, index, 'screen'))
      : [{
          id: 'screen-1',
          title: 'Primary Screen',
          kind: 'screen',
          size: { width: 0, height: 0 },
          nav: [],
          fields: [],
          tables: [],
          keyTexts: uniqueLabels(texts.slice(0, 60).map((text) => text.text), 60),
        }];

    const summarizedDialogs = dialogCandidates.map((dialog, index) => summarizeContainer(dialog, elements, texts, index, 'dialog'));

    return {
      meta: {
        sourceFormat: 'Excalidraw',
        originalElementCount: elements.length,
        screenCount: summarizedScreens.length,
        dialogCount: summarizedDialogs.length,
      },
      theme: {
        topStrokeColors: topColors(elements, 'strokeColor', 8),
        topFillColors: topColors(elements, 'backgroundColor', 8),
      },
      screens: summarizedScreens,
      dialogs: summarizedDialogs,
      looseTexts: uniqueLabels(texts.filter((text) => text.text.length >= 3).map((text) => text.text), 80),
    };
  }

  function binaryFromText(propertyName, fileName, text, mimeType) {
    return [
      propertyName,
      {
        data: Buffer.from(String(text || ''), 'utf8').toString('base64'),
        fileName,
        mimeType,
      },
    ];
  }
  function compactRequirementsText(text) {
    return String(text || '')
      .replace(/\\u0000/g, '')
      .replace(/\\r\\n/g, '\\n')
      .replace(/\\r/g, '\\n')
      .replace(/[ \\t]+/g, ' ')
      .trim();
  }

  function compactOpenapiText(text) {
    const normalized = normalizeText(text);
    if (!normalized) return '';
    if (normalized.startsWith('{')) {
      try {
        return JSON.stringify(JSON.parse(normalized));
      } catch {}
    }
    return normalized.replace(/[ \\t]+$/gm, '').replace(/\\n{3,}/g, '\\n\\n');
  }
  let requirements = null;
  let openapi = null;
  let design = null;
  for (let itemIndex = 0; itemIndex < items.length; itemIndex += 1) {
    if (!requirements) requirements = await readBinaryText.call(this, itemIndex, 'requirements', 'requirements-compact.txt');
    if (!openapi) openapi = await readBinaryText.call(this, itemIndex, 'openapiSpec', 'openapi-compact.json');
    if (!design) design = await readBinaryText.call(this, itemIndex, 'design', 'design.excalidraw.json');
  }

  if (!requirements) throw new Error('Missing compact requirements binary for frontend context.');
  if (!openapi) throw new Error('Missing compact openapiSpec binary for frontend context.');
  if (!design) throw new Error('Missing design binary for frontend context.');
  const compactedRequirementsText = compactRequirementsText(requirements.text);
  if (!compactedRequirementsText) throw new Error('Requirements text is empty after frontend compaction.');
  const compactedOpenapiText = compactOpenapiText(openapi.text);
  if (!compactedOpenapiText) throw new Error('OpenAPI text is empty after frontend compaction.');

  const designRaw = normalizeText(design.text);
  if (!designRaw) {
    throw new Error('Design text is empty, cannot compact frontend design context.');
  }

  let designObject;
  try {
    designObject = JSON.parse(designRaw);
  } catch (error) {
    throw new Error('Failed to parse design JSON for frontend context compaction: ' + String(error?.message || error));
  }

  const compactedDesign = summarizeDesign(designObject);
  const compactedDesignText = JSON.stringify(compactedDesign);

  return [{
    json: {
      designCompactionStats: {
        sourceBytes: Buffer.byteLength(designRaw, 'utf8'),
        compactBytes: Buffer.byteLength(compactedDesignText, 'utf8'),
        screenCount: compactedDesign.meta.screenCount,
        dialogCount: compactedDesign.meta.dialogCount,
      },
    },
    binary: Object.fromEntries([
      binaryFromText('requirements', 'requirements-compact.txt', compactedRequirementsText, 'text/plain'),
      binaryFromText('openapiSpec', 'openapi-compact.json', compactedOpenapiText, 'application/json'),
      binaryFromText('designSpec', 'design-compact.json', compactedDesignText, 'application/json'),
    ]),
  }];
}

return await feCompactContextArtifacts.call(this);

async function feBuildPrompt() {
  const items = $input.all();
  if (!items.length) {
    throw new Error('Frontend structure prompt builder received no input.');
  }

  async function readBinaryText(itemIndex, propertyName, fallbackFileName) {
    const item = items[itemIndex];
    const binary = item.binary?.[propertyName];
    if (!binary) return null;

    const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, propertyName);
    return {
      fileName: binary.fileName || fallbackFileName,
      text: buffer.toString('utf8'),
    };
  }

  let requirements = null;
  let openapi = null;
  let design = null;

  for (let itemIndex = 0; itemIndex < items.length; itemIndex += 1) {
    if (!requirements) {
      requirements = await readBinaryText.call(this, itemIndex, 'requirements', 'requirements-compact.txt');
    }
    if (!openapi) {
      openapi = await readBinaryText.call(this, itemIndex, 'openapiSpec', 'openapi-compact.json');
    }
    if (!design) {
      design = await readBinaryText.call(this, itemIndex, 'designSpec', 'design-compact.json');
    }
  }

  if (!requirements) {
    throw new Error('Missing compact requirements binary for frontend structure generation.');
  }
  if (!openapi) {
    throw new Error('Missing compact openapiSpec binary for frontend structure generation.');
  }
  if (!design) {
    throw new Error('Missing compact designSpec binary for frontend structure generation.');
  }

  const requirementsText = String(requirements.text || '').trim();
  const openapiText = String(openapi.text || '').trim();
  const designText = String(design.text || '').trim();
  if (!requirementsText) {
    throw new Error('Requirements text is empty for frontend structure generation.');
  }
  if (!openapiText) {
    throw new Error('OpenAPI text is empty for frontend structure generation.');
  }
  if (!designText) {
    throw new Error('Design text is empty for frontend structure generation.');
  }

  const userPrompt = [
    'REQ',
    requirementsText,
    'API',
    openapiText,
    'DESIGN',
    designText,
  ].join('\n');

  return [{
    json: {
      requirementsFile: requirements.fileName,
      requirementsText,
      requirementsPromptLength: requirementsText.length,
      openapiFile: openapi.fileName || 'openapi-compact.json',
      openapiText,
      openapiPromptLength: openapiText.length,
      designFile: design.fileName || 'design-compact.json',
      designText,
      designPromptLength: designText.length,
      userPrompt,
      fullPromptLength: userPrompt.length,
    },
    binary: items[0].binary ?? {},
  }];
}

return await feBuildPrompt.call(this);

?function joinContentBlocks(value) {
  if (!Array.isArray(value)) return '';
  const parts = value
    .map((entry) => {
      if (typeof entry === 'string') return entry;
      if (entry && typeof entry.text === 'string') return entry.text;
      if (entry && typeof entry.content === 'string') return entry.content;
      return '';
    })
    .filter((entry) => entry && entry.trim());
  return parts.join('\n').trim();
}

function toTokenCount(value) {
  const parsed = Number(value);
  if (!Number.isFinite(parsed) || parsed < 0) return null;
  return Math.trunc(parsed);
}

function extractUsageTokensObject(obj) {
  if (!obj || typeof obj !== 'object') return null;
  const candidates = [
    obj.usage?.completion_tokens,
    obj.usage?.output_tokens,
    obj.usage?.completionTokens,
    obj.usage?.outputTokens,
    obj.completion_tokens,
    obj.output_tokens,
    obj.data?.usage?.completion_tokens,
    obj.data?.usage?.output_tokens,
    obj.choices?.[0]?.usage?.completion_tokens,
    obj.choices?.[0]?.usage?.output_tokens,
  ];
  for (const candidate of candidates) {
    const count = toTokenCount(candidate);
    if (count !== null) return count;
  }
  return null;
}

function extractTextFromChunk(chunk) {
  const candidates = [
    chunk?.choices?.[0]?.delta?.content,
    chunk?.choices?.[0]?.message?.content,
    chunk?.choices?.[0]?.text,
    chunk?.message?.content,
    chunk?.response,
    chunk?.output,
    chunk?.result,
    chunk?.data?.choices?.[0]?.delta?.content,
    chunk?.data?.choices?.[0]?.message?.content,
    chunk?.data?.choices?.[0]?.text,
    chunk?.data?.response,
    chunk?.data?.output,
    chunk?.data?.result,
  ];

  for (const value of candidates) {
    if (typeof value === 'string' && value.length) return value;
    if (Array.isArray(value)) {
      const joined = joinContentBlocks(value);
      if (joined) return joined;
    }
  }
  return '';
}

function parseStreamChunks(value) {
  if (typeof value !== 'string') {
    return { text: '', tokenCount: null, parsedAny: false, lastChunk: null };
  }

  const raw = value.trim();
  if (!raw) {
    return { text: '', tokenCount: null, parsedAny: false, lastChunk: null };
  }

  const lines = raw.split(/\r?\n/);
  const textParts = [];
  let parsedAny = false;
  let lastChunk = null;
  let lastTokenCount = null;

  for (const rawLine of lines) {
    const line = rawLine.trim();
    if (!line) continue;

    let payload = line;
    if (line.startsWith('data:')) payload = line.slice(5).trim();
    if (!payload || payload === '[DONE]') continue;

    try {
      const chunk = JSON.parse(payload);
      parsedAny = true;
      if (chunk && typeof chunk === 'object') lastChunk = chunk;
      const tokens = extractUsageTokensObject(chunk);
      if (tokens !== null) lastTokenCount = tokens;
      const text = extractTextFromChunk(chunk);
      if (text) textParts.push(text);
    } catch {
      // ignore non-json lines
    }
  }

  return {
    text: textParts.join(''),
    tokenCount: lastTokenCount,
    parsedAny,
    lastChunk,
  };
}

function extractUsageTokensFromAny(value, seen = new Set(), depth = 0) {
  if (value === null || typeof value === 'undefined') return null;
  if (depth > 6) return null;

  if (typeof value === 'string') {
    const stream = parseStreamChunks(value);
    if (stream.tokenCount !== null) return stream.tokenCount;
    try {
      const parsed = JSON.parse(value);
      return extractUsageTokensFromAny(parsed, seen, depth + 1);
    } catch {
      return null;
    }
  }

  if (Array.isArray(value)) {
    let last = null;
    for (const entry of value) {
      const token = extractUsageTokensFromAny(entry, seen, depth + 1);
      if (token !== null) last = token;
    }
    return last;
  }

  if (typeof value === 'object') {
    if (seen.has(value)) return null;
    seen.add(value);

    const direct = extractUsageTokensObject(value);
    if (direct !== null) return direct;

    const candidates = [
      value.data,
      value.response,
      value.output,
      value.result,
      value.text,
      value.choices,
    ];

    for (const candidate of candidates) {
      const token = extractUsageTokensFromAny(candidate, seen, depth + 1);
      if (token !== null) return token;
    }
  }

  return null;
}

function normalizeStreamingText(value) {
  if (typeof value !== 'string') return '';
  const text = value.trim();
  if (!text) return '';

  const parsed = parseStreamChunks(text);
  if (parsed.text && parsed.text.trim()) return parsed.text;

  if (parsed.parsedAny && parsed.lastChunk && typeof parsed.lastChunk === 'object') {
    const fallback = extractTextFromChunk(parsed.lastChunk);
    if (fallback && fallback.trim()) return fallback;
  }

  return text;
}

function firstText(...values) {
  for (const value of values) {
    if (typeof value === 'string' && value.trim()) {
      const normalized = normalizeStreamingText(value);
      if (normalized && normalized.trim()) return normalized.trim();
    }

    const joined = joinContentBlocks(value);
    if (joined) {
      const normalized = normalizeStreamingText(joined);
      if (normalized && normalized.trim()) return normalized.trim();
    }
  }
  return '';
}

function parseMaybeJson(value) {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  if (!trimmed.startsWith('{') && !trimmed.startsWith('[') && !trimmed.startsWith('"')) return null;
  try {
    return JSON.parse(trimmed);
  } catch {
    return null;
  }
}

function decodeEscapedText(text) {
  const value = String(text ?? '');
  const trimmed = value.trim();
  if (!trimmed) return '';

  // Only decode when the whole payload is itself a quoted JSON string.
  if (trimmed.startsWith('"') && trimmed.endsWith('"')) {
    try {
      const parsed = JSON.parse(trimmed);
      if (typeof parsed === 'string') return parsed;
    } catch {
      // fall through
    }
  }

  return value;
}

function stripCodeFence(text) {
  const value = String(text ?? '').trim();
  if (!value) return '';
  const fenced = value.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fenced) return fenced[1].trim();
  return value;
}

function extractModelText(json) {
  if (!json || typeof json !== 'object') return '';

  const direct = firstText(
    json.text,
    json.response,
    json.output,
    json.result,
    json.answer,
    json.completion,
    json.generated_text,
    json.message?.content,
    json.choices?.[0]?.message?.content,
    json.choices?.[0]?.text,
    json.data?.text,
    json.data?.response,
    json.data?.output,
    json.data?.result,
    json.data?.choices?.[0]?.message?.content,
    json.data?.choices?.[0]?.text,
    json.content,
    json.data?.content,
    json.data,
  );

  if (direct) return direct;

  const parsedFromStrings = [json.response, json.text, json.output, json.result, json.data]
    .map((value) => parseMaybeJson(value))
    .filter((value) => value && typeof value === 'object');

  for (const parsed of parsedFromStrings) {
    const parsedText = extractModelText(parsed);
    if (parsedText) return parsedText;
  }

  return '';
}

function extractOutputTokens(json, rawModelText) {
  const direct = extractUsageTokensObject(json);
  if (direct !== null) {
    return { outputTokens: direct, outputTokensSource: 'usage.completion_tokens' };
  }

  const fromNested = extractUsageTokensFromAny([json.data, json.response, json.output, json.result, json.text]);
  if (fromNested !== null) {
    return { outputTokens: fromNested, outputTokensSource: 'stream.usage.completion_tokens' };
  }

  const estimated = Math.max(1, Math.round(String(rawModelText ?? '').length / 4));
  return { outputTokens: estimated, outputTokensSource: 'estimated_char_div4' };
}

function normalizeFiles(value) {
  const files = Array.isArray(value) ? value : [];
  const normalized = [];

  for (const entry of files) {
    if (!entry || typeof entry !== 'object') continue;
    const rawPath = String(entry.path ?? '').trim().replace(/\\/g, '/');
    if (!rawPath) continue;

    const prefixedPath = rawPath.startsWith('frontend/')
      ? rawPath
      : `frontend/${rawPath.replace(/^\/+/, '')}`;
    const path = prefixedPath.replace(/\/+/g, '/');

    const hasTraversal = (
      path.includes('/../')
      || path.startsWith('../')
      || path.endsWith('/..')
      || path.includes('/./')
      || path.startsWith('frontend/../')
      || path.includes(':')
      || path.endsWith('/')
    );
    if (hasTraversal) continue;

    const blockedPrefixes = [
      'frontend/main/',
      'frontend/target/',
      'frontend/node_modules/',
      'frontend/.git/',
      'frontend/.idea/',
      'frontend/.vscode/',
      'frontend/.DS_Store',
    ];
    if (blockedPrefixes.some((prefix) => path.startsWith(prefix) || path === prefix.replace(/\/$/, ''))) {
      continue;
    }

    if (!path.startsWith('frontend/')) continue;

    let content = '';
    if (typeof entry.content === 'string') content = entry.content;
    else if (entry.content === null || typeof entry.content === 'undefined') content = '';
    else if (typeof entry.content === 'object') content = JSON.stringify(entry.content, null, 2);
    else content = String(entry.content);

    normalized.push({ path, content });
  }

  if (!normalized.length) {
    throw new Error('Frontend files JSON does not contain any valid files under frontend/ after path sanitization.');
  }

  const hasReadme = normalized.some((entry) => entry.path === 'frontend/README.md');
  if (!hasReadme) {
    // Best effort: continue even when README entry is missing/truncated in model output.
    // Upstream prompt still requests README generation.
  }

  return normalized;
}

function findMatchingBracket(text, startIndex, openChar, closeChar) {
  let depth = 0;
  let inString = false;
  let quote = '';
  let escaped = false;

  for (let i = startIndex; i < text.length; i += 1) {
    const ch = text[i];

    if (inString) {
      if (escaped) {
        escaped = false;
      } else if (ch === '\\') {
        escaped = true;
      } else if (ch === quote) {
        inString = false;
        quote = '';
      }
      continue;
    }

    if (ch === '"' || ch === "'") {
      inString = true;
      quote = ch;
      continue;
    }

    if (ch === openChar) depth += 1;
    else if (ch === closeChar) {
      depth -= 1;
      if (depth === 0) return i;
    }
  }

  return -1;
}

function splitTopLevelObjectsInArray(arrayText) {
  const objects = [];
  let inString = false;
  let quote = '';
  let escaped = false;
  let depth = 0;
  let start = -1;

  for (let i = 0; i < arrayText.length; i += 1) {
    const ch = arrayText[i];

    if (inString) {
      if (escaped) escaped = false;
      else if (ch === '\\') escaped = true;
      else if (ch === quote) { inString = false; quote = ''; }
      continue;
    }

    if (ch === '"' || ch === "'") {
      inString = true;
      quote = ch;
      continue;
    }

    if (ch === '{') {
      if (depth === 0) start = i;
      depth += 1;
      continue;
    }

    if (ch === '}') {
      if (depth <= 0) {
        depth = 0;
        start = -1;
        continue;
      }

      depth -= 1;
      if (depth === 0 && start >= 0) {
        objects.push(arrayText.slice(start, i + 1));
        start = -1;
      }
    }
  }

  return objects;
}

function extractFieldExpression(objectText, fieldName) {
  const keyRegex = new RegExp(`"${fieldName}"\\s*:`);
  const match = keyRegex.exec(objectText);
  if (!match) return null;

  let i = match.index + match[0].length;
  while (i < objectText.length && /\s/.test(objectText[i])) i += 1;

  const start = i;
  let inString = false;
  let quote = '';
  let escaped = false;
  let curly = 0;
  let square = 0;
  let paren = 0;

  for (; i < objectText.length; i += 1) {
    const ch = objectText[i];

    if (inString) {
      if (escaped) escaped = false;
      else if (ch === '\\') escaped = true;
      else if (ch === quote) { inString = false; quote = ''; }
      continue;
    }

    if (ch === '"' || ch === "'") {
      inString = true;
      quote = ch;
      continue;
    }

    if (ch === '{') curly += 1;
    else if (ch === '}') {
      if (curly === 0 && square === 0 && paren === 0) break;
      curly = Math.max(0, curly - 1);
    } else if (ch === '[') square += 1;
    else if (ch === ']') square = Math.max(0, square - 1);
    else if (ch === '(') paren += 1;
    else if (ch === ')') paren = Math.max(0, paren - 1);
    else if (ch === ',' && curly === 0 && square === 0 && paren === 0) break;
  }

  return objectText.slice(start, i).trim();
}

function unescapeLiteralText(value) {
  return String(value ?? '')
    .replace(/\\r\\n/g, '\n')
    .replace(/\\n/g, '\n')
    .replace(/\\r/g, '\r')
    .replace(/\\t/g, '\t')
    .replace(/\\"/g, '"')
    .replace(/\\'/g, "'")
    .replace(/\\\\/g, '\\');
}

function parseConcatenatedStringExpression(expr) {
  const text = String(expr ?? '').trim();
  if (!text) return '';

  const literals = [];
  let i = 0;
  while (i < text.length) {
    const ch = text[i];
    if (ch !== '"' && ch !== "'") {
      i += 1;
      continue;
    }

    const quote = ch;
    i += 1;
    let current = '';
    let escaped = false;

    while (i < text.length) {
      const c = text[i];
      i += 1;

      if (escaped) {
        current += '\\' + c;
        escaped = false;
        continue;
      }

      if (c === '\\') {
        escaped = true;
        continue;
      }

      if (c === quote) break;
      current += c;
    }

    literals.push(unescapeLiteralText(current));
  }

  if (!literals.length) return text;

  const merged = literals.join('');
  return merged.replace(/"n"/g, '\n');
}

function extractFilesFromJsLikeText(rawText) {
  const stripped = stripCodeFence(decodeEscapedText(rawText));
  if (!stripped) return null;

  const filesKeyIndex = stripped.indexOf('"files"');
  if (filesKeyIndex < 0) return null;

  const arrayStart = stripped.indexOf('[', filesKeyIndex);
  if (arrayStart < 0) return null;

  const arrayEnd = findMatchingBracket(stripped, arrayStart, '[', ']');
  const arrayText = arrayEnd >= 0
    ? stripped.slice(arrayStart, arrayEnd + 1)
    : stripped.slice(arrayStart);

  if (!arrayText.trim()) return null;
  const objectTexts = splitTopLevelObjectsInArray(arrayText);
  if (!objectTexts.length) return null;

  const files = [];
  for (const objectText of objectTexts) {
    const pathExpr = extractFieldExpression(objectText, 'path');
    const contentExpr = extractFieldExpression(objectText, 'content');
    if (!pathExpr || !contentExpr) continue;

    const path = parseConcatenatedStringExpression(pathExpr).trim();
    if (!path) continue;

    let content = '';
    const trimmedContentExpr = contentExpr.trim();
    if (trimmedContentExpr.startsWith('{') || trimmedContentExpr.startsWith('[')) {
      try {
        content = JSON.stringify(JSON.parse(trimmedContentExpr), null, 2);
      } catch {
        content = trimmedContentExpr;
      }
    } else {
      content = parseConcatenatedStringExpression(trimmedContentExpr);
    }

    files.push({ path, content });
  }

  if (!files.length) return null;
  return normalizeFiles(files);
}

function parseJsonObjectFromText(text) {
  const normalized = stripCodeFence(decodeEscapedText(text));

  const direct = parseMaybeJson(normalized);
  if (direct && typeof direct === 'object') return direct;
  if (typeof direct === 'string') {
    const nested = parseMaybeJson(direct);
    if (nested && typeof nested === 'object') return nested;
  }

  const objectStart = normalized.indexOf('{');
  const objectEnd = normalized.lastIndexOf('}');
  if (objectStart >= 0 && objectEnd > objectStart) {
    const candidate = normalized.slice(objectStart, objectEnd + 1);
    const parsed = parseMaybeJson(candidate);
    if (parsed && typeof parsed === 'object') return parsed;
  }

  const arrayStart = normalized.indexOf('[');
  const arrayEnd = normalized.lastIndexOf(']');
  if (arrayStart >= 0 && arrayEnd > arrayStart) {
    const candidate = normalized.slice(arrayStart, arrayEnd + 1);
    const parsed = parseMaybeJson(candidate);
    if (Array.isArray(parsed)) return { files: parsed };
  }

  return null;
}

function tryExtractFiles(value, seen = new Set(), depth = 0) {
  if (value === null || typeof value === 'undefined') return null;
  if (depth > 8) return null;

  if (Array.isArray(value)) {
    try {
      return normalizeFiles(value);
    } catch {
      const chunkText = value
        .map((entry) => (entry && typeof entry === 'object') ? extractTextFromChunk(entry) : String(entry ?? ''))
        .join('');
      if (chunkText.trim()) {
        const nested = tryExtractFiles(chunkText, seen, depth + 1);
        if (nested) return nested;
      }
      for (const entry of value) {
        const nested = tryExtractFiles(entry, seen, depth + 1);
        if (nested) return nested;
      }
      return null;
    }
  }

  if (typeof value === 'string') {
    const parsedObj = parseJsonObjectFromText(value);
    if (parsedObj) {
      const nested = tryExtractFiles(parsedObj, seen, depth + 1);
      if (nested) return nested;
    }

    const jsLike = extractFilesFromJsLikeText(value);
    if (jsLike) return jsLike;

    const normalized = normalizeStreamingText(value);
    if (normalized && normalized !== value) {
      const nested = tryExtractFiles(normalized, seen, depth + 1);
      if (nested) return nested;
    }

    return null;
  }

  if (typeof value === 'object') {
    if (seen.has(value)) return null;
    seen.add(value);

    if (Array.isArray(value.files)) {
      try {
        return normalizeFiles(value.files);
      } catch {
        const fallback = tryExtractFiles(value.files, seen, depth + 1);
        if (fallback) return fallback;
      }
    }

    if (Array.isArray(value.frontendFiles)) {
      try {
        return normalizeFiles(value.frontendFiles);
      } catch {
        const fallback = tryExtractFiles(value.frontendFiles, seen, depth + 1);
        if (fallback) return fallback;
      }
    }

    const nestedCandidates = [
      value.response,
      value.output,
      value.result,
