      .filter(([key]) => !String(key).endsWith('_firstIteration')),
  );
}

function normalizeFiles(value) {
  const files = Array.isArray(value) ? value : [];
  const normalized = [];
  const seen = new Set();

  for (const entry of files) {
    const candidatePath = typeof entry === 'string'
      ? entry
      : (entry && typeof entry === 'object' ? String(entry.path ?? '') : '');

    const rawPath = String(candidatePath || '').trim().replace(/\\/g, '/');
    if (!rawPath) continue;

    const prefixedPath = rawPath.startsWith('frontend/')
      ? rawPath
      : `frontend/${rawPath.replace(/^\/+/, '')}`;
    const path = prefixedPath.replace(/\/+/g, '/');

    const hasTraversal = (
      path.includes('/../')
      || path.startsWith('../')
      || path.endsWith('/..')
      || path.includes('/./')
      || path.startsWith('frontend/../')
      || path.includes(':')
      || path.endsWith('/')
    );
    if (hasTraversal) continue;

    const blockedPrefixes = [
      'frontend/main/',
      'frontend/target/',
      'frontend/node_modules/',
      'frontend/.git/',
      'frontend/.idea/',
      'frontend/.vscode/',
      'frontend/.DS_Store',
    ];
    if (blockedPrefixes.some((prefix) => path.startsWith(prefix) || path === prefix.replace(/\/$/, ''))) {
      continue;
    }

    if (!path.startsWith('frontend/')) continue;

    if (seen.has(path)) continue;
    seen.add(path);
    normalized.push({ path });
  }

  return normalized;
}

